const files = $json.files || [];
if (!files.length) throw new Error('Nenhum arquivo encontrado');
return [{ json: files[0] }];

function excelSerialToDate(serialNumber) {
  const excelEpoch = new Date(Date.UTC(1899, 11, 30));
  return new Date(excelEpoch.getTime() + Number(serialNumber) * 86400000);
}

function parseDate(value) {
  if (!value || value === '') return null;
  if (value instanceof Date && !isNaN(value)) return value;
  if (typeof value === 'number') {
    const date = excelSerialToDate(value);
    return isNaN(date) ? null : date;
  }
  const str = String(value).trim();
  const ddmmyyyy = str.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
  if (ddmmyyyy) {
    const [_, day, month, year] = ddmmyyyy;
    const date = new Date(Date.UTC(Number(year), Number(month) - 1, Number(day)));
    return isNaN(date) ? null : date;
  }
  const isoDate = new Date(str);
  return isNaN(isoDate) ? null : isoDate;
}

function formatDateISO(date) {
  const year = date.getUTCFullYear();
  const month = String(date.getUTCMonth() + 1).padStart(2, '0');
  const day = String(date.getUTCDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
}

// Normaliza texto para comparação: 'OBSERVAÇÃO GRD' -> 'observacaogrd'
// Remove acentos, símbolos e espaços
function normalizeKey(key) {
  if (!key) return '';
  return key.toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, "") // Remove acentos
    .replace(/[^a-z0-9]/g, ""); // Mantém apenas letras e números
}

// Encontra o valor na linha usando busca aproximada (fuzzy)
function getFuzzyField(row, targetKeywords) {
  const rowKeys = Object.keys(row);
  const normalizedTarget = normalizeKey(targetKeywords);

  // 1. Tenta match exato primeiro (normalizado)
  for (const key of rowKeys) {
    if (normalizeKey(key) === normalizedTarget) return row[key];
  }

  // 2. Se não achou, tenta match parcial (ex: 'obs grd' contém 'grd'? Cuidado com falso positivo)
  // Vamos usar uma lista de possibilidades exatas definidas na chamada
  return null;
}

function getField(row, ...variants) {
  const rowKeys = Object.keys(row);

  for (const variant of variants) {
    const normalizedVariant = normalizeKey(variant);
    for (const key of rowKeys) {
      if (normalizeKey(key) === normalizedVariant) {
        const val = row[key];
        if (val !== undefined && val !== null) return val;
      }
    }
  }
  return null;
}

function normalize(value) {
  if (value === null || value === undefined) return null;
  const str = String(value).trim();
  return str === '' ? null : str;
}

const items = $input.all();
if (!items.length) return [];

const processedRows = [];

for (const item of items) {
  const row = item.json || {};

  const chapa = normalize(getField(row, 'MAT', 'MATRICULA', 'CHAPA'));
  const nome = normalize(getField(row, 'NOME', 'NOME COMPLETO', 'FUNCIONARIO'));
  if (!chapa || !nome) continue;

  const funcao = normalize(getField(row, 'FUNCAO', 'FUNÇÃO', 'CARGO'));
  const status = normalize(getField(row, 'STATUS', 'SITUACAO'));
  const area = normalize(getField(row, 'AREA', 'ÁREA', 'DEPARTAMENTO'));
  const cid = normalize(getField(row, 'CIP DE LIBERAÇÃO', 'CIP DE LIBERACAO', 'CID', 'cid', 'UG', 'U.G', 'UNIDADE'));
  const rh = normalize(getField(row, 'RH', 'rh'));
  const saude = normalize(getField(row, 'SAÚDE', 'SAUDE', 'saude'));
  const seguranca = normalize(getField(row, 'SEGURANÇA', 'SEGURANCA', 'seguranca'));
  const grd = normalize(getField(row, 'GRD', 'grd'));
  const obs_grd = normalize(getField(row, 'OBSERVAÇÃO GRD', 'OBSERVACAO GRD', 'OBS GRD', 'obs_grd', 'OBSERVACOES', 'OBS'));

  const dataAcessoRaw = normalize(getField(row, 'DATA ACESSO', 'ACESSO PROJETO'));
  const dataAdmissaoRaw = normalize(getField(row, 'ADMISSAO', 'DATA ADMISSAO', 'DATA DE ADMISSAO'));
  const liberacaoRaw = normalize(getField(row, 'DATA DE LIBERAÇÃO E-COORDINA', 'DATA DE LIBERACAO E-COORDINA', 'liberacao_ecoordin'));
  const envioClienteRaw = normalize(getField(row, 'ENVIO CLIENTE', 'DATA ENVIO CLIENTE', 'ENVIO AO CLIENTE', 'DATA DE ENVIO', 'envio_cliente'));

  const dataAcessoDate = parseDate(dataAcessoRaw);
  const dataAdmissaoDate = parseDate(dataAdmissaoRaw);
  const liberacaoDate = parseDate(liberacaoRaw);

  // --- FILTRO DE DATA (Solicitação: 01/01/2026 até Hoje) ---
  const FILTER_START = new Date('2026-01-01T00:00:00.000Z');
  const FILTER_END = new Date(); // Data/Hora atual do servidor
  FILTER_END.setDate(FILTER_END.getDate() - 1);

  // Se não tiver data de admissão válida, ignoramos o registro (conforme regra restritiva)
  // Se quiser incluir sem data, mude para: if (dataAdmissaoDate && ...)
  if (!dataAdmissaoDate) continue;

  // Verifica intervalo
  if (dataAdmissaoDate < FILTER_START || dataAdmissaoDate > FILTER_END) {
      continue; // Pula este registro se estiver fora do período
  }
  // -----------------------------------------------------------

  // envio_cliente é salvo como texto, mas vamos tentar formatar se for data, senão mantém original
  const envioClienteDate = parseDate(envioClienteRaw);
  const envioClienteFinal = envioClienteDate ? formatDateISO(envioClienteDate) : envioClienteRaw;

  const rowData = {
    chapa: String(chapa),
    nome: String(nome),
    funcao,
    status,
    area,
    cid,
    rh,
    saude,
    seguranca,
    grd,
    obs_grd,
    envio_cliente: envioClienteFinal,
    data_acesso_projeto: dataAcessoDate ? formatDateISO(dataAcessoDate) : null,
    data_admissao: dataAdmissaoDate ? formatDateISO(dataAdmissaoDate) : null,
    liberacao_ecoordin: liberacaoDate ? formatDateISO(liberacaoDate) : null
  };

  processedRows.push({ json: rowData });
}

return processedRows;

// --- OTIMIZAÇÃO DE PERFORMANCE ---

// 1. Carrega todos os itens da planilha (do nó de Transformação direto)
const planilhaItems = $('Transformar_Dados').all();

// 2. Carrega todos os itens do banco (input deste nó)
const supabaseItems = $input.all();

// 3. Cria um Mapa (Índice) dos dados do banco para busca rápida por CHAPA
// Ex: { '12345': { ...dados_do_banco }, '67890': { ... } }
const bancoMap = {};
for (const item of supabaseItems) {
    if (item.json && item.json.chapa) {
        bancoMap[String(item.json.chapa)] = item.json;
    }
}

const results = [];

// 4. Itera sobre CADA item da planilha
for (const pItem of planilhaItems) {
    // AVISO: Agora lemos direto do nó de transformação, que retorna o JSON plano, sem o wrapper 'planilha_data'
    const planilhaData = pItem.json;
    if (!planilhaData || !planilhaData.chapa) continue;

    const chapa = String(planilhaData.chapa);

    // Busca instantânea no Mapa
    const dadosBanco = bancoMap[chapa];
    const existeNoBanco = !!dadosBanco;

    // --- DECISÃO ---

    // CASO 1: INSERT (Não existe no banco)
    if (!existeNoBanco) {
        results.push({
            json: {
                operation: 'INSERT',
                ...planilhaData
            }
        });
        continue;
    }

    // CASO 2: VERIFICAR MUDANÇAS (Existe)
    const updateFields = {};
    let hasChanges = false;
    const ignoreFields = ['id', 'created_at', 'updated_at', 'last_modified', 'operation'];

    for (const key of Object.keys(planilhaData)) {
        if (ignoreFields.includes(key)) continue;

        const valorPlanilha = planilhaData[key];
        const valorBanco = dadosBanco[key];

        const vP = valorPlanilha === null || valorPlanilha === undefined ? '' : String(valorPlanilha);
        const vB = valorBanco === null || valorBanco === undefined ? '' : String(valorBanco);

        if (vP !== vB) {
            updateFields[key] = valorPlanilha;
            hasChanges = true;
        }
    }

    if (hasChanges) {
        results.push({
            json: {
                operation: 'UPDATE',
                chapa: chapa,
                updateFields: updateFields
            }
        });
    } else {
        results.push({
            json: {
                operation: 'SKIP',
                chapa: chapa,
                message: 'Dados idênticos'
            }
        });
    }
}

return results;
